svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
var svg         = document.getElementById('root');
  var dataLayerEl = document.getElementById('data-layer');
  var structuralOverlayEl = document.getElementById('structural-overlay');
  var cells = Array.prototype.slice.call(dataLayerEl.querySelectorAll('.mcell'));

  /* §3 — Method A1: animationend + .visible, setTimeout gates .ready */
  var duration = 0.8;
  var lastDelay = 0;
  cells.forEach(function(cell) {
    var delay = parseFloat(cell.getAttribute('data-delay') || '0');
    if (delay > lastDelay) lastDelay = delay;
    cell.style.animation = 'cellFade ' + duration + 's ease-out ' + delay.toFixed(2) + 's';
    cell.addEventListener('animationend', function() {
      cell.style.animation = 'none';
      cell.classList.add('visible');
    }, { once: true });
  });
  if (structuralOverlayEl) {
    structuralOverlayEl.style.animation = 'cellFade ' + duration + 's ease-out 0s';
    structuralOverlayEl.addEventListener('animationend', function() {
      structuralOverlayEl.style.animation = 'none';
      structuralOverlayEl.classList.add('visible');
    }, { once: true });
  }
  setTimeout(function() { dataLayerEl.classList.add('ready'); }, (lastDelay + duration + 0.1) * 1000);

  /* §4 — Tooltip (JS-driven, 3-element tip-bg + tip-border + tip-tail) */
  var BH = 58, TH = 10, RX = 8, TW = 8;
  var tip    = document.getElementById('tip');
  var tipBg  = document.getElementById('tip-bg');
  var tipBdr = document.getElementById('tip-bdr');
  var tipTip = document.getElementById('tip-tip');
  var tipVal = document.getElementById('tip-val');
  var tipLbl = document.getElementById('tip-lbl');
  var tipPct = document.getElementById('tip-pct');

  function positionTip(mx, my, name, val, pct) {
    /* 1 — set text content first so getBBox() measures real rendered width */
    var parts = name.split(' · ');
    tipVal.textContent = parts[0];
    tipLbl.textContent = parts[1] || '';
    tipPct.textContent = 'Value: ' + val + '  ·  ' + pct + ' of product';

    /* 2 — measure widest line, derive hw (half-width), minimum 60px total */
    var pad = 20;
    var hw = Math.max(
      tipVal.getBBox().width + pad,
      tipLbl.getBBox().width + pad,
      tipPct.getBBox().width + pad,
      60
    ) / 2;
    var BW = hw * 2;

    /* 3 — clamp tx so bubble stays inside viewBox */
    var tx = Math.max(hw + 8, Math.min(mx, 1100 - hw - 8));

    /* 4 — flip: show below cursor when near top */
    var flip = my < BH + TH + 20;
    var boxY = flip ? my + TH : my - TH - BH;
    var L = tx - hw, R = tx + hw, T = boxY, B = boxY + BH;

    /* tip-bg rect */
    tipBg.setAttribute('x',      L);
    tipBg.setAttribute('y',      T);
    tipBg.setAttribute('width',  BW);
    tipBg.setAttribute('height', BH);

    /* tip-border open path — all absolute, 1px inset at tail root to close seam */
    var openD, tailD;
    if (!flip) {
      /* tail points down: gap in bottom edge */
      openD = 'M'+(tx+TW)+','+B+
              ' L'+(R-RX)+','+B+' Q'+R+','+B+' '+R+','+(B-RX)+
              ' L'+R+','+(T+RX)+' Q'+R+','+T+' '+(R-RX)+','+T+
              ' L'+(L+RX)+','+T+' Q'+L+','+T+' '+L+','+(T+RX)+
              ' L'+L+','+(B-RX)+' Q'+L+','+B+' '+(L+RX)+','+B+
              ' L'+(tx-TW)+','+B;
      tailD = 'M'+(tx-TW)+','+B+' L'+tx+','+(B+TH)+' L'+(tx+TW)+','+B;
    } else {
      /* tail points up: gap in top edge */
      openD = 'M'+(tx-TW)+','+T+
              ' L'+(L+RX)+','+T+' Q'+L+','+T+' '+L+','+(T+RX)+
              ' L'+L+','+(B-RX)+' Q'+L+','+B+' '+(L+RX)+','+B+
              ' L'+(R-RX)+','+B+' Q'+R+','+B+' '+R+','+(B-RX)+
              ' L'+R+','+(T+RX)+' Q'+R+','+T+' '+(R-RX)+','+T+
              ' L'+(tx+TW)+','+T;
      tailD = 'M'+(tx+TW)+','+T+' L'+tx+','+(T-TH)+' L'+(tx-TW)+','+T;
    }
    tipBdr.removeAttribute('transform');
    tipBdr.setAttribute('d', openD);
    tipTip.setAttribute('d', tailD);

    /* text positions */
    var textY = boxY + 14;
    tipVal.setAttribute('x', tx); tipVal.setAttribute('y', textY);
    tipLbl.setAttribute('x', tx); tipLbl.setAttribute('y', textY + 18);
    tipPct.setAttribute('x', tx); tipPct.setAttribute('y', textY + 34);
  }

  /* §4 — Hover: .hovering on container, .hovered on item */
  cells.forEach(function(cell) {
    var name = cell.getAttribute('data-name');
    var val  = cell.getAttribute('data-val');
    var pct  = cell.getAttribute('data-pct');
    cell.addEventListener('mouseenter', function(e) {
      cells.forEach(function(c) { c.classList.remove('hovered'); });
      dataLayerEl.classList.add('hovering');
      cell.classList.add('hovered');
      tip.style.opacity = '1';
      var pt = svg.createSVGPoint();
      pt.x = e.clientX; pt.y = e.clientY;
      var sp = pt.matrixTransform(svg.getScreenCTM().inverse());
      positionTip(sp.x, sp.y, name, val, pct);
    });
    cell.addEventListener('mousemove', function(e) {
      var pt = svg.createSVGPoint();
      pt.x = e.clientX; pt.y = e.clientY;
      var sp = pt.matrixTransform(svg.getScreenCTM().inverse());
      positionTip(sp.x, sp.y, name, val, pct);
    });
    cell.addEventListener('mouseleave', function() {
      dataLayerEl.classList.remove('hovering');
      cell.classList.remove('hovered');
      tip.style.opacity = '';
    });
  });

  /* §2 — Dark mode toggle: isDark boolean, CSS handles palette swap */
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
